194→    // MARK: - Message Bubble
195→
196→    private func messageBubble(for message: AIChatMessage) -> some View {
197→        let isUser = message.role == .user
198→
199→        return HStack {
200→            if isUser { Spacer(minLength: 60) }
201→
202→            Text(message.content)
203→                .font(FitTodayFont.ui(size: 14, weight: .medium))
204→                .foregroundStyle(isUser ? .white : FitTodayColor.textPrimary)
205→                .padding(.horizontal, FitTodaySpacing.md)
206→                .padding(.vertical, 10)
207→                .background(isUser ? FitTodayColor.brandPrimary : FitTodayColor.surfaceElevated)
208→                .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))
209→
210→            if !isUser { Spacer(minLength: 60) }
211→        }
212→        .padding(.horizontal, FitTodaySpacing.md)
213→    }
214→
215→    // MARK: - Input Bar
216→
217→    private var inputBar: some View {
218→        HStack(spacing: FitTodaySpacing.sm) {
219→            TextField("fitorb.input_placeholder".localized, text: $viewModel.inputText)
220→                .font(FitTodayFont.ui(size: 16, weight: .medium))
221→                .foregroundStyle(FitTodayColor.textPrimary)
222→                .padding(.horizontal, FitTodaySpacing.md)
223→                .padding(.vertical, 10)
224→                .background(FitTodayColor.surfaceElevated)
225→                .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.lg))
226→                .onSubmit {
227→                    viewModel.sendMessage()
228→                }
229→
230→            Button {
231→                viewModel.sendMessage()
232→            } label: {
233→                Image(systemName: "arrow.up.circle.fill")
234→                    .font(.system(size: 32))
235→                    .foregroundStyle(
236→                        viewModel.inputText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
237→                            ? FitTodayColor.textTertiary
238→                            : FitTodayColor.brandPrimary
239→                    )
240→            }
241→            .disabled(viewModel.inputText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || viewModel.isLoading || viewModel.isTyping)
242→        }
243→        .padding(.horizontal, FitTodaySpacing.md)
244→        .padding(.vertical, FitTodaySpacing.sm)
245→        .background(FitTodayColor.surface)
246→    }
247→
248→    private func scrollToBottom(proxy: ScrollViewProxy) {
249→        if let lastMessage = viewModel.messages.last {
250→            withAnimation {
251→                proxy.scrollTo(lastMessage.id, anchor: .bottom)
252→            }
253→        }
254→    }
255→
256→}
