  7→
  8→import Foundation
  9→import SwiftData
 10→import Combine
 11→
 12→@MainActor
 13→final class StoreKitEntitlementRepository: EntitlementRepository, @unchecked Sendable {
 14→    private let modelContainer: ModelContainer
 15→    private let storeKitService: StoreKitService
 16→    private var latest: ProEntitlement
 17→    private var streamContinuation: AsyncStream<ProEntitlement>.Continuation?
 18→    private var cancellables = Set<AnyCancellable>()
 19→    
 20→    private lazy var stream: AsyncStream<ProEntitlement> = {
 21→        AsyncStream { continuation in
 22→            continuation.yield(latest)
 23→            continuation.onTermination = { _ in }
 24→            self.streamContinuation = continuation
 25→        }
 26→    }()
 27→
 28→    init(modelContainer: ModelContainer, storeKitService: StoreKitService) {
 29→        self.modelContainer = modelContainer
 30→        self.storeKitService = storeKitService
 31→        
 32→        // Carregar do cache local primeiro (startup rápido)
 33→        if let snapshot = try? Self.fetchSnapshot(from: modelContainer) {
 34→            latest = EntitlementMapper.toDomain(snapshot)
 35→        } else {
 36→            latest = .free
 37→        }
 38→        
 39→        // Observar mudanças no StoreKitService
 40→        setupSubscriptionObserver()
 41→        
 42→        // Verificar status atual do StoreKit em background
 43→        Task {
 44→            await refreshFromStoreKit()
 45→        }
 46→    }
 47→    
 48→    private func setupSubscriptionObserver() {
 49→        // 💡 Learn: Com @Observable, usamos withObservationTracking para observar mudanças
 50→        Task {
 51→            var previousValue = storeKitService.hasProAccess
 52→            while !Task.isCancelled {
 53→                let currentValue = await withObservationTracking {
 54→                    storeKitService.hasProAccess
 55→                } onChange: {
 56→                    // Retorna quando há mudança
 57→                }
 58→
 59→                if currentValue != previousValue {
 60→                    await handleSubscriptionChange(currentValue)
 61→                    previousValue = currentValue
 62→                }
 63→
 64→                // Pequeno delay para evitar loop muito apertado
 65→                try? await Task.sleep(nanoseconds: 100_000_000) // 100ms
 66→            }
 67→        }
 68→    }
 69→    
 70→    private func handleSubscriptionChange(_ hasPro: Bool) async {
 71→        let entitlement = await storeKitService.getCurrentEntitlement()
 72→        await updateEntitlement(entitlement)
 73→    }
 74→    
 75→    private func refreshFromStoreKit() async {
 76→        await storeKitService.refreshPurchaseStatus()
 77→        let entitlement = await storeKitService.getCurrentEntitlement()
 78→        await updateEntitlement(entitlement)
 79→    }
 80→
 81→    func currentEntitlement() async throws -> ProEntitlement {
 82→        latest
 83→    }
 84→
 85→    func entitlementStream() -> AsyncStream<ProEntitlement> {
 86→        _ = stream
 87→        return stream
 88→    }
 89→    
 90→    private func updateEntitlement(_ entitlement: ProEntitlement) async {
 91→        guard entitlement != latest else { return }
 92→        latest = entitlement
 93→        streamContinuation?.yield(entitlement)
 94→        try? Self.save(snapshot: entitlement, in: modelContainer)
 95→    }
 96→    
 97→    // MARK: - StoreKit Service Access
 98→    
 99→    var service: StoreKitService {
100→        storeKitService
101→    }
102→
103→    // MARK: - Persistence
104→
105→    private static func fetchSnapshot(from container: ModelContainer) throws -> SDProEntitlementSnapshot? {
106→        let context = ModelContext(container)
107→        var descriptor = FetchDescriptor<SDProEntitlementSnapshot>()
108→        descriptor.fetchLimit = 1
109→        return try context.fetch(descriptor).first
110→    }
111→
112→    private static func save(snapshot entitlement: ProEntitlement, in container: ModelContainer) throws {
113→        let context = ModelContext(container)
114→        var descriptor = FetchDescriptor<SDProEntitlementSnapshot>()
115→        descriptor.fetchLimit = 1
116→        if let existing = try context.fetch(descriptor).first {
117→            existing.isPro = entitlement.isPro
118→            existing.sourceRaw = entitlement.source.rawValue
119→            existing.expirationDate = entitlement.expirationDate
120→            existing.updatedAt = Date()
121→        } else {
122→            context.insert(EntitlementMapper.toSnapshot(entitlement))
123→        }
124→        try context.save()
125→    }
126→}
