289→private final class InMemoryProfileRepository: UserProfileRepository, @unchecked Sendable {
290→    private var profile: UserProfile?
291→    func loadProfile() async throws -> UserProfile? { profile }
292→    func saveProfile(_ profile: UserProfile) async throws { self.profile = profile }
293→}
294→
295→private final class InMemoryEntitlementRepository: EntitlementRepository, @unchecked Sendable {
296→    func currentEntitlement() async throws -> ProEntitlement { .free }
297→    func entitlementStream() -> AsyncStream<ProEntitlement> {
298→        AsyncStream { continuation in continuation.finish() }
299→    }
300→}
301→
302→private final class InMemoryHistoryRepository: WorkoutHistoryRepository {
303→    private var entries: [WorkoutHistoryEntry] = []
304→
305→    func listEntries() async throws -> [WorkoutHistoryEntry] {
306→        entries.sorted { $0.date > $1.date }
307→    }
308→    
309→    func listEntries(limit: Int, offset: Int) async throws -> [WorkoutHistoryEntry] {
310→        let sorted = entries.sorted { $0.date > $1.date }
311→        let start = min(offset, sorted.count)
312→        let end = min(offset + limit, sorted.count)
313→        return Array(sorted[start..<end])
314→    }
315→    
316→    func count() async throws -> Int {
317→        entries.count
318→    }
319→
320→    func saveEntry(_ entry: WorkoutHistoryEntry) async throws {
321→        entries.append(entry)
322→    }
323→
324→    func listAppEntriesWithPlan(limit: Int) async throws -> [WorkoutHistoryEntry] {
325→        let filtered = entries
326→            .filter { $0.source == .app && $0.workoutPlan != nil }
327→            .sorted { $0.date > $1.date }
328→        return Array(filtered.prefix(limit))
