216→        return HStack {
217→            if isUser { Spacer(minLength: 60) }
218→
219→            Text(message.content)
220→                .font(FitTodayFont.ui(size: 14, weight: .medium))
221→                .foregroundStyle(isUser ? .white : FitTodayColor.textPrimary)
222→                .padding(.horizontal, FitTodaySpacing.md)
223→                .padding(.vertical, 10)
224→                .background(isUser ? FitTodayColor.brandPrimary : FitTodayColor.surfaceElevated)
225→                .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))
226→
227→            if !isUser { Spacer(minLength: 60) }
