238→                .foregroundStyle(FitTodayColor.textPrimary)
239→                .padding(.horizontal, FitTodaySpacing.md)
240→                .padding(.vertical, 10)
241→                .background(FitTodayColor.surfaceElevated)
242→                .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.lg))
243→                .onSubmit {
244→                    viewModel.sendMessage()
245→                }
246→
247→            Button {
248→                viewModel.sendMessage()
249→            } label: {
250→                Image(systemName: "arrow.up.circle.fill")
251→                    .font(.system(size: 32))
252→                    .foregroundStyle(
253→                        viewModel.inputText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
254→                            ? FitTodayColor.textTertiary
255→                            : FitTodayColor.brandPrimary
256→                    )
257→            }
258→            .disabled(viewModel.inputText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || viewModel.isLoading || viewModel.isTyping)
259→        }
260→        .padding(.horizontal, FitTodaySpacing.md)
261→        .padding(.vertical, FitTodaySpacing.sm)
262→        .background(FitTodayColor.surface)
263→    }
264→
265→    private func scrollToBottom(proxy: ScrollViewProxy) {
266→        if let lastMessage = viewModel.messages.last {
267→            withAnimation {
268→                proxy.scrollTo(lastMessage.id, anchor: .bottom)
269→            }
270→        }
271→    }
