 8→import SwiftUI
 9→
10→struct TrainerHistoryView: View {
11→    let workouts: [TrainerWorkout]
12→
13→    private var thisWeekWorkouts: [TrainerWorkout] {
14→        let calendar = Calendar.current
15→        let weekStart = calendar.date(from: calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: Date())) ?? Date()
16→        return workouts.filter { $0.createdAt >= weekStart }.sorted { $0.createdAt > $1.createdAt }
17→    }
18→
19→    private var lastWeekWorkouts: [TrainerWorkout] {
20→        let calendar = Calendar.current
21→        let weekStart = calendar.date(from: calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: Date())) ?? Date()
22→        let lastWeekStart = calendar.date(byAdding: .weekOfYear, value: -1, to: weekStart) ?? Date()
23→        return workouts.filter { $0.createdAt >= lastWeekStart && $0.createdAt < weekStart }.sorted { $0.createdAt > $1.createdAt }
24→    }
25→
26→    private var olderWorkouts: [TrainerWorkout] {
27→        let calendar = Calendar.current
28→        let weekStart = calendar.date(from: calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: Date())) ?? Date()
29→        let lastWeekStart = calendar.date(byAdding: .weekOfYear, value: -1, to: weekStart) ?? Date()
30→        return workouts.filter { $0.createdAt < lastWeekStart }.sorted { $0.createdAt > $1.createdAt }
31→    }
32→
33→    var body: some View {
34→        ScrollView {
35→            if workouts.isEmpty {
36→                emptyView
37→            } else {
38→                LazyVStack(alignment: .leading, spacing: FitTodaySpacing.lg) {
39→                    if !thisWeekWorkouts.isEmpty {
40→                        sectionView(title: "trainer.history.this_week".localized, workouts: thisWeekWorkouts)
41→                    }
42→
43→                    if !lastWeekWorkouts.isEmpty {
44→                        sectionView(title: "trainer.history.last_week".localized, workouts: lastWeekWorkouts)
45→                    }
46→
47→                    if !olderWorkouts.isEmpty {
48→                        sectionView(title: "trainer.history.older".localized, workouts: olderWorkouts)
49→                    }
50→                }
51→                .padding(.horizontal, FitTodaySpacing.md)
52→                .padding(.vertical, FitTodaySpacing.sm)
53→            }
54→        }
55→        .scrollIndicators(.hidden)
56→        .background(FitTodayColor.background)
57→    }
