//
//  TrainerChatView.swift
//  FitToday
//
//  Chat interface for communicating with a personal trainer.
//

import SwiftUI

struct TrainerChatView: View {
    @State private var viewModel: TrainerChatViewModel

    init(trainerId: String, trainerName: String) {
        _viewModel = State(wrappedValue: TrainerChatViewModel(trainerId: trainerId, trainerName: trainerName))
    }

    var body: some View {
        VStack(spacing: 0) {
            // Messages
            ScrollViewReader { proxy in
                ScrollView {
                    LazyVStack(spacing: FitTodaySpacing.sm) {
                        ForEach(viewModel.messages) { message in
                            ChatBubble(
                                message: message,
                                isFromCurrentUser: !message.isFromTrainer
                            )
                            .id(message.id)
                        }
                    }
                    .padding(.horizontal, FitTodaySpacing.md)
                    .padding(.vertical, FitTodaySpacing.sm)
                }
                .scrollIndicators(.hidden)
                .onChange(of: viewModel.messages.count) {
                    if let lastId = viewModel.messages.last?.id {
                        withAnimation {
                            proxy.scrollTo(lastId, anchor: .bottom)
                        }
                    }
                }
            }

            Divider()
                .overlay(FitTodayColor.outline)

            // Input Bar
            inputBar
        }
        .background(FitTodayColor.background)
    }

    // MARK: - Input Bar

    private var inputBar: some View {
        HStack(spacing: FitTodaySpacing.sm) {
            TextField("trainer.chat.placeholder".localized, text: $viewModel.newMessageText, axis: .vertical)
                .font(FitTodayFont.ui(size: 14, weight: .medium))
                .foregroundStyle(FitTodayColor.textPrimary)
                .lineLimit(1...4)
                .padding(.horizontal, FitTodaySpacing.md)
                .padding(.vertical, 10)
                .background(FitTodayColor.surface)
                .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))

            Button {
                viewModel.sendMessage()
            } label: {
                Image(systemName: "arrow.up.circle.fill")
                    .font(.system(size: 32))
                    .foregroundStyle(viewModel.canSend ? FitTodayColor.brandPrimary : FitTodayColor.textTertiary)
            }
            .buttonStyle(.plain)
            .disabled(!viewModel.canSend)
        }
        .padding(.horizontal, FitTodaySpacing.md)
        .padding(.vertical, FitTodaySpacing.sm)
        .background(FitTodayColor.backgroundElevated)
    }
}

//
//  TrainerChatViewModel.swift
//  FitToday
//
//  ViewModel for trainer chat interface.
//  Currently uses mock data — real chat backend to be integrated later.
//

import Foundation

/// A single chat message between trainer and student.
struct ChatMessage: Identifiable, Sendable {
    let id: String
    let text: String
    let senderId: String
    let timestamp: Date
    let isFromTrainer: Bool
}

@MainActor
@Observable final class TrainerChatViewModel {
    private(set) var messages: [ChatMessage] = []
    var newMessageText = ""

    private let trainerId: String
    private let trainerName: String

    var canSend: Bool {
        !newMessageText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    init(trainerId: String, trainerName: String) {
        self.trainerId = trainerId
        self.trainerName = trainerName
        loadMockMessages()
    }

    func sendMessage() {
        guard canSend else { return }
        let message = ChatMessage(
            id: UUID().uuidString,
            text: newMessageText.trimmingCharacters(in: .whitespacesAndNewlines),
            senderId: "current_user",
            timestamp: Date(),
            isFromTrainer: false
        )
        messages.append(message)
        newMessageText = ""
    }

    private func loadMockMessages() {
        let calendar = Calendar.current
        let now = Date()
        messages = [
            ChatMessage(id: "1", text: "trainer.chat.mock.msg1".localized, senderId: trainerId, timestamp: calendar.date(byAdding: .hour, value: -2, to: now)!, isFromTrainer: true),
            ChatMessage(id: "2", text: "trainer.chat.mock.msg2".localized, senderId: "current_user", timestamp: calendar.date(byAdding: .hour, value: -1, to: now)!, isFromTrainer: false),
            ChatMessage(id: "3", text: "trainer.chat.mock.msg3".localized, senderId: trainerId, timestamp: calendar.date(byAdding: .minute, value: -45, to: now)!, isFromTrainer: true),
            ChatMessage(id: "4", text: "trainer.chat.mock.msg4".localized, senderId: "current_user", timestamp: calendar.date(byAdding: .minute, value: -30, to: now)!, isFromTrainer: false),
            ChatMessage(id: "5", text: "trainer.chat.mock.msg5".localized, senderId: trainerId, timestamp: calendar.date(byAdding: .minute, value: -10, to: now)!, isFromTrainer: true),
        ]
    }
}

//
//  ChatBubble.swift
//  FitToday
//
//  Chat message bubble component for trainer-student communication.
//

import SwiftUI

struct ChatBubble: View {
    let message: ChatMessage
    let isFromCurrentUser: Bool

    var body: some View {
        HStack {
            if isFromCurrentUser { Spacer(minLength: 60) }

            VStack(alignment: isFromCurrentUser ? .trailing : .leading, spacing: 4) {
                Text(message.text)
                    .font(FitTodayFont.ui(size: 14, weight: .medium))
                    .foregroundStyle(isFromCurrentUser ? .white : FitTodayColor.textPrimary)
                    .padding(.horizontal, FitTodaySpacing.md)
                    .padding(.vertical, 10)
                    .background(isFromCurrentUser ? FitTodayColor.brandPrimary : FitTodayColor.surfaceElevated)
                    .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))

                Text(message.timestamp.formatted(date: .omitted, time: .shortened))
                    .font(FitTodayFont.ui(size: 11, weight: .medium))
                    .foregroundStyle(FitTodayColor.textTertiary)
            }

            if !isFromCurrentUser { Spacer(minLength: 60) }
        }
    }
}

