### 7. **Real-time Firestore Snapshot Listeners Pattern**

**Template (from FirebaseNotificationService):**

```swift
func observeRelationship(studentId: String) -> AsyncStream<TrainerStudentRelationship?> {
    AsyncStream { continuation in
        let listener = relationshipsCollection
            .whereField("studentId", isEqualTo: studentId)
            .addSnapshotListener { snapshot, error in
                if let error = error {
                    #if DEBUG
                    print("[Service] Observe error: \(error.localizedDescription)")
                    #endif
                    return
                }

                guard let snapshot = snapshot else { return }

                do {
                    let results = try snapshot.documents.compactMap { doc in
                        let model = try doc.data(as: FBTrainerStudent.self)
                        return (doc.documentID, model)
                    }
                    continuation.yield(results.first)
                } catch {
                    continuation.yield(nil)
                }
            }

        continuation.onTermination = { _ in
            listener.remove()  // CRITICAL: Clean up listener
        }
    }
}
```

