### 10. **PersonalTrainer Firebase Service Pattern (Template for Chat Service)**

**Architecture Pattern to Follow:**

**Service Layer (Actor):**
```swift
actor FirebaseTrainerChatService {
    private let db = Firestore.firestore()

    private var messagesCollection: CollectionReference {
        db.collection("trainerMessages")
    }

    // Single read
    func fetchMessages(trainerId: String, studentId: String) async throws -> [FBTrainerMessage] {
        let snapshot = try await messagesCollection
            .whereField("trainerId", isEqualTo: trainerId)
            .whereField("studentId", isEqualTo: studentId)
            .order(by: "createdAt", descending: false)
            .getDocuments()

        return snapshot.documents.compactMap { doc in
            try? doc.data(as: FBTrainerMessage.self)
        }
    }

    // Real-time updates
    func observeMessages(trainerId: String, studentId: String) -> AsyncStream<[FBTrainerMessage]> {
        AsyncStream { continuation in
            let listener = messagesCollection
                .whereField("trainerId", isEqualTo: trainerId)
                .whereField("studentId", isEqualTo: studentId)
                .order(by: "createdAt", descending: false)
                .addSnapshotListener { snapshot, error in
                    // Handle updates
                    continuation.yield(messages)
                }

            continuation.onTermination = { _ in
                listener.remove()
            }
        }
    }

    // Write
    func sendMessage(_ message: FBTrainerMessage) async throws {
        try await messagesCollection.addDocument(from: message)
    }
}
```

**Repository Layer:**
```swift
final class FirebaseTrainerChatRepository: TrainerChatRepository {
    private let service: FirebaseTrainerChatService

    func fetchMessages(trainerId: String, studentId: String) async throws -> [TrainerChatMessage] {
        let fbMessages = try await service.fetchMessages(trainerId: trainerId, studentId: studentId)
        return fbMessages.map { TrainerChatMessageMapper.toDomain($0) }
    }

    func observeMessages(trainerId: String, studentId: String) -> AsyncStream<[TrainerChatMessage]> {
        AsyncStream { continuation in
            Task {
                let stream = await service.observeMessages(trainerId: trainerId, studentId: studentId)
                for await fbMessages in stream {
                    let messages = fbMessages.map { TrainerChatMessageMapper.toDomain($0) }
                    continuation.yield(messages)
                }
                continuation.finish()
            }
        }
    }
}
```

